using namespace std;

class DSU {
public:
    vector<int> parent;
    // diff[i]: the parity (0 or 1) of the path weight from node i to parent[i]
    vector<int> diff;
    int n;

    DSU(int size) : n(size) {
        parent.resize(n);
        iota(parent.begin(), parent.end(), 0);
        diff.assign(n, 0);
    }

    // Finds the representative (root) of the set containing i,
    // and updates diff[i] to be the parity of the path weight from i to the root.
    int find(int i) {
        if (parent[i] == i) {
            return i;
        }
        int root = find(parent[i]);

        // Path compression: Update diff[i] relative to the new root
        // New diff[i] = (old_diff[i] + diff[parent[i]]_after_recursion) mod 2
        diff[i] = (diff[i] + diff[parent[i]]) % 2;

        parent[i] = root;
        return root;
    }

    // Attempts to unite sets containing u and v with edge weight w.
    // Returns true if the edge was added (no cycle or cycle parity is even), false otherwise.
    bool unite(int u, int v, int w) {
        int rootU = find(u);
        int rootV = find(v);

        if (rootU != rootV) {
            // Case 1: u and v are in different components. Adding the edge is always safe (no cycle).

            // Union: Make rootU the child of rootV (arbitrary choice)
            parent[rootU] = rootV;

            // Update the path parity (diff[rootU]):
            // We need diff[rootU] = parity(rootU -> rootV).
            // We know: parity(u -> v) = w
            // We know: parity(u -> rootU) = diff[u]
            // We know: parity(v -> rootV) = diff[v]
            // Since the path in the new graph is u -> ... -> rootU -> rootV -> ... -> v, and we want u -> v = w
            // path(u -> rootU) + path(rootU -> rootV) + path(rootV -> v) = w (mod 2)
            // diff[u] + diff[rootU] + diff[v] = w (mod 2)
            // diff[rootU] = w - diff[u] - diff[v] (mod 2)
            // Since we are in mod 2 arithmetic, subtraction is addition:
            diff[rootU] = (w + diff[u] + diff[v]) % 2;

            return true;
        } else {
            // Case 2: u and v are already in the same component. Adding the edge creates a cycle.
            // The path weight from u to v through the existing tree structure is:
            // Path(u -> rootU) + Path(rootU -> v) = diff[u] + diff[v] (mod 2)

            // The cycle weight is: 
            // Cycle_weight = Path(u -> v, existing) + w (new edge weight) (mod 2)
            // Cycle_weight = (diff[u] + diff[v] + w) (mod 2)

            // The condition requires Cycle_weight to be 0 (even).
            if ((diff[u] + diff[v] + w) % 2 == 0) {
                // The cycle sum is even, so we add the edge.
                // The DSU structure remains consistent since we didn't change parent pointers.
                return true;
            }
            // Cycle sum is odd, so we discard the edge.
            return false;
        }
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges) {
    DSU dsu(n);
    long long addedEdgesCount = 0;

    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long w = edge[2];

        if (dsu.unite(u, v, (int)w)) {
            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}

