            // 1. path_weight(u, rootU) = diff[u] (mod 2)
            // 2. path_weight(v, rootV) = diff[v] (mod 2)
            // 3. path_weight(rootU, rootV) is what we set (diff[rootU])
            // 
            // We need: path_weight(u, rootU) + path_weight(rootU, rootV) + path_weight(rootV, v) = w (mod 2)
            // Wait, this is complex. Let's use the direct relationship:
            // path_weight(u, v) = w (mod 2)
            // path_weight(u, rootU) + path_weight(rootU, rootV) + path_weight(rootV, v) = w (mod 2) (if we traverse through the new edge)

            // Simpler approach for setting diff[rootU]:
            // We are setting parent[rootU] = rootV. We need diff[rootU] = parity(rootU -> rootV).
            // We know: parity(u -> v) = w
            // We also know: parity(u -> rootU) = diff[u]
            // So, parity(rootU -> v) = parity(rootU -> u) + w = diff[u] + w (mod 2).
            // And parity(rootV -> v) = diff[v].
            // We need parity(rootU -> rootV).
            // parity(rootU -> rootV) = parity(rootU -> u) + parity(u -> v) + parity(v -> rootV)
            // Since parity(u -> rootU) = diff[u] and parity(rootU -> u) = diff[u] (as it's undirected),
            // and parity(v -> rootV) = diff[v], then parity(rootV -> v) = diff[v].
            // parity(rootU -> rootV) = diff[u] + w + diff[v] (mod 2)

            diff[rootU] = (diff[u] + w + diff[v]) % 2;

            addedEdgesCount++;

        } else {
            // Case 2: u and v are already in the same component.
            // Adding this edge creates a cycle.
            // The cycle path is: u -> rootU -> v -> u (via the new edge).
            // The path weight from u to v through the existing tree structure is:
            // Path(u -> rootU) + Path(rootU -> v) = diff[u] + diff[v] (mod 2)

            // The cycle weight is: 
            // Cycle_weight = Path(u -> v, existing) + w (new edge weight) (mod 2)
            // Cycle_weight = (diff[u] + diff[v] + w) (mod 2)

            // The condition requires Cycle_weight to be 0 (even).
            // (diff[u] + diff[v] + w) % 2 === 0

            if ((diff[u] + diff[v] + w) % 2 === 0) {
                // The cycle sum is even, so we add the edge.
                addedEdgesCount++;

                // Although it doesn't change the component structure, we should conceptually merge
                // the paths if we were using a strict cycle basis, but here, since the parity matches,
                // the DSU structure remains consistent. No change to parent/diff is strictly needed
                // for correctness in the DSU structure itself, as we found the condition holds.
                // The paths still align modulo 2.
            }
        }
    }

    return addedEdgesCount;
